#include <stdio.h>

int* nextSmallerElement(int* arr, int n) {
    static int ans[100000];
    for (int i = 0; i < n; i++) {
        ans[i] = -1;
        for (int j = i + 1; j < n; j++) {
            if (arr[j] < arr[i]) {
                ans[i] = arr[j];
                break;
            }
        }
    }
    return ans;
}

int main() {
    int arr[] = {4, 8, 5, 2, 25};
    int n = sizeof(arr) / sizeof(arr[0]);
    int* ans = nextSmallerElement(arr, n);
    for (int i = 0; i < n; i++) {
        printf("%d ", ans[i]);
    }
    return 0;
}

