import java.util.*;

class Solution {
    public int[] nextSmallerElement(int[] arr) {
        int n = arr.length;
        int[] ans = new int[n];
        Arrays.fill(ans, -1);
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (arr[j] < arr[i]) {
                    ans[i] = arr[j];
                    break;
                }
            }
        }
        return ans;
    }
}

public class Main {
    public static void main(String[] args) {
        int[] arr = {4, 8, 5, 2, 25};
        Solution sol = new Solution();
        int[] ans = sol.nextSmallerElement(arr);
        System.out.print("The next smaller elements are: ");
        for (int num : ans) {
            System.out.print(num + " ");
        }
    }
}

